#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

typedef struct SinglyLinkedList {
    Node* head;
} SinglyLinkedList;

typedef struct DoublyNode {
    int data;
    struct DoublyNode* next;
    struct DoublyNode* prev;
} DoublyNode;

typedef struct DoublyLinkedList {
    DoublyNode* head;
} DoublyLinkedList;

Node* createNode(int data) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

DoublyNode* createDoublyNode(int data) {
    DoublyNode* newNode = (DoublyNode*)malloc(sizeof(DoublyNode));
    newNode->data = data;
    newNode->next = NULL;
    newNode->prev = NULL;
    return newNode;
}

void appendSingly(SinglyLinkedList* list, int data) {
    Node* newNode = createNode(data);
    if (!list->head) {
        list->head = newNode;
        return;
    }
    Node* current = list->head;
    while (current->next) {
        current = current->next;
    }
    current->next = newNode;
}

void appendDoubly(DoublyLinkedList* list, int data) {
    DoublyNode* newNode = createDoublyNode(data);
    if (!list->head) {
        list->head = newNode;
        return;
    }
    DoublyNode* current = list->head;
    while (current->next) {
        current = current->next;
    }
    current->next = newNode;
    newNode->prev = current;
}

void deleteDoubly(DoublyLinkedList* list, int data) {
    DoublyNode* current = list->head;
    while (current && current->data != data) {
        current = current->next;
    }
    if (current) {
        if (current->prev) {
            current->prev->next = current->next;
        } else {
            list->head = current->next;
        }
        if (current->next) {
            current->next->prev = current->prev;
        }
        free(current);
    }
}

void printList(Node* head) {
    printf("[");
    Node* current = head;
    while (current) {
        printf("%d", current->data);
        if (current->next) printf(", ");
        current = current->next;
    }
    printf("]\n");
}

void printDoublyList(DoublyNode* head) {
    printf("[");
    DoublyNode* current = head;
    while (current) {
        printf("%d", current->data);
        if (current->next) printf(", ");
        current = current->next;
    }
    printf("]\n");
}

void freeSinglyList(Node* head) {
    Node* current = head;
    while (current) {
        Node* temp = current;
        current = current->next;
        free(temp);
    }
}

void freeDoublyList(DoublyNode* head) {
    DoublyNode* current = head;
    while (current) {
        DoublyNode* temp = current;
        current = current->next;
        free(temp);
    }
}

