    SinglyLinkedList sll = {NULL};
    DoublyLinkedList dll = {NULL};
    int values[] = {5, 10, 15};
    for (int i = 0; i < 3; i++) {
        appendSingly(&sll, values[i]);
        appendDoubly(&dll, values[i]);
    }
    printf("Singly Linked List: ");
    printList(sll.head);
    deleteDoubly(&dll, 10);
    printf("Doubly Linked List after deleting 10: ");
    printDoublyList(dll.head);
    freeSinglyList(sll.head);
    freeDoublyList(dll.head);
    return 0;
}
